using System.ComponentModel.DataAnnotations;

namespace sv_ac51d2d51c3d49edbbdb27ce9f660241.Services;

public class Step1Model
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone number is required.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = "";
}

public class Step2Model
{
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = "";

    [Required(ErrorMessage = "Appointment date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string ReasonForVisit { get; set; } = "";
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult(ErrorMessage);
        }
        return ValidationResult.Success;
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_ac51d2d51c3d49edbbdb27ce9f660241.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

@if (isBooked)
{
    <div class="alert alert-success mt-3">
        <strong>Appointment booked!</strong> We'll send a confirmation to <strong>@step1.Email</strong>.
    </div>
}
else
{
    <h5>Step 1: Patient Information</h5>
    <EditForm EditContext="step1Context" FormName="step1" OnValidSubmit="HandleStep1Valid">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="step1.PatientName" />
            <ValidationMessage For="() => step1.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="step1.Email" />
            <ValidationMessage For="() => step1.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="step1.Phone" />
            <ValidationMessage For="() => step1.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="step1.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => step1.InsuranceProvider" />
        </div>

        <button type="submit" class="btn btn-primary">Next</button>
    </EditForm>

    @if (showStep2)
    {
        <hr class="my-4" />
        <h5>Step 2: Appointment Details</h5>

        <EditForm EditContext="step2Context" FormName="step2" OnSubmit="HandleStep2Submit">
            <DataAnnotationsValidator />
            <CustomValidator @ref="customValidator" />

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="step2.Doctor" @bind:after="OnDoctorChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc.Name">@doc.Name</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => step2.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Appointment Date</label>
                <InputDate class="form-control" @bind-Value="step2.AppointmentDate" @bind:after="OnDateChanged" />
                <ValidationMessage For="() => step2.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="step2.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => step2.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" rows="3" @bind-Value="step2.ReasonForVisit" />
                <ValidationMessage For="() => step2.ReasonForVisit" />
            </div>

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Checking..." : "Check Availability & Book")
            </button>
            <button type="button" class="btn btn-outline-secondary ms-2" @onclick="GoBackToStep1">
                Back
            </button>
        </EditForm>
    }
}

@code {
    private Step1Model step1 = new();
    private Step2Model step2 = new();
    private EditContext step1Context = default!;
    private EditContext step2Context = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isBooked;
    private bool isSubmitting;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        step1Context = new EditContext(step1);
        step2Context = new EditContext(step2);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void HandleStep1Valid()
    {
        showStep2 = true;
    }

    private async Task OnDoctorChanged()
    {
        await LoadSlots();
    }

    private async Task OnDateChanged()
    {
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        if (!string.IsNullOrEmpty(step2.Doctor) && step2.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                step2.Doctor, step2.AppointmentDate.Value);
        }
        else
        {
            availableSlots = [];
        }

        step2.TimeSlot = "";
    }

    private async Task HandleStep2Submit()
    {
        customValidator?.ClearErrors();

        if (!step2Context.Validate())
            return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                step1.Email, step1.InsuranceProvider, step2.Doctor, step2.TimeSlot);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            await AppointmentSvc.BookAppointmentAsync(new AppointmentModel
            {
                PatientName = step1.PatientName,
                Email = step1.Email,
                Phone = step1.Phone,
                InsuranceProvider = step1.InsuranceProvider,
                Doctor = step2.Doctor,
                AppointmentDate = step2.AppointmentDate,
                TimeSlot = step2.TimeSlot,
                ReasonForVisit = step2.ReasonForVisit,
            });

            isBooked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void GoBackToStep1()
    {
        showStep2 = false;
    }
}

